func solve(nums []int64, queries [][]int64) int64 {
	mod := 109 + 7
	n := len(nums)
	multipliers := make([]int64, n)
	for i := range multipliers {
		multipliers[i] = 1
	}

	for _, q := range queries {
		li := q[0]
		ri := q[1]
		ki := q[2]
		vi := q[3]
		idx := li
		for idx <= ri {
			multipliers[idx] = (multipliers[idx] * vi) % mod
			idx += ki
		}
	}

	result := int64(0)
	for i := 0; i < n; i++ {
		result ^= (nums[i] * multipliers[i]) % mod
	}
	return result
}
